import{_ as e,o,c as s,a as t,b as i}from"./index-BVGI5laF.js";const n={class:"legal-section"},l={__name:"PoliticaPrivacidad",setup(d){return o(()=>{document.title="Política de Privacidad | Reglado Maps"}),(r,a)=>(i(),s("section",n,[...a[0]||(a[0]=[t('<div class="legal-card" data-v-716b8056><h1 class="h1" data-v-716b8056>Política de Privacidad</h1><div class="legal-content" data-v-716b8056><p data-v-716b8056><strong data-v-716b8056>1. ¿QUIÉN ES EL RESPONSABLE DEL TRATAMIENTO DE SUS DATOS?</strong></p><p data-v-716b8056>El responsable del tratamiento de los datos personales es REGLADO GROUP S.L, con CIF B23982762 y domicilio en AVDA. ISLA GRACIOSA, 7 PISO 1º DESPACHOS 5-6 28703 SAN SEBASTIÁN DE LOS REYES (Madrid).</p><p data-v-716b8056>Contacto: info@regladoconsultores.com</p><p data-v-716b8056><strong data-v-716b8056>2. ¿CON QUÉ FINALIDAD TRATAMOS SUS DATOS PERSONALES?</strong></p><p data-v-716b8056>En REGLADO GROUP S.L tratamos la información que nos facilitan las personas interesadas con las siguientes finalidades en el marco de Reglado Maps:</p><ul data-v-716b8056><li data-v-716b8056>Gestionar el acceso a la plataforma cartográfica y sus funcionalidades.</li><li data-v-716b8056>Tramitar solicitudes de información técnica sobre activos energéticos.</li><li data-v-716b8056>Mejorar la experiencia de usuario mediante el análisis de la interacción con el mapa.</li><li data-v-716b8056>Remitir comunicaciones sobre actualizaciones de la plataforma cuando sea autorizado.</li></ul><p data-v-716b8056><strong data-v-716b8056>3. ¿POR CUÁNTO TIEMPO CONSERVAREMOS SUS DATOS?</strong></p><p data-v-716b8056>Los datos personales proporcionados se conservarán mientras se mantenga la relación contractual/comercial o durante los años necesarios para cumplir con las obligaciones legales.</p><p data-v-716b8056><strong data-v-716b8056>4. ¿CUÁL ES LA LEGITIMACIÓN PARA EL TRATAMIENTO DE SUS DATOS?</strong></p><p data-v-716b8056>La base legal para el tratamiento de sus datos es el consentimiento del interesado al acceder a la plataforma o al realizar consultas específicas.</p><p data-v-716b8056><strong data-v-716b8056>5. ¿A QUÉ DESTINATARIOS SE COMUNICARÁN SUS DATOS?</strong></p><p data-v-716b8056>Los datos no se cederán a terceros salvo en los casos en que exista una obligación legal o sea necesario para la prestación del servicio geoespacial solicitado.</p><p data-v-716b8056><strong data-v-716b8056>6. ¿CUÁLES SON SUS DERECHOS AL FACILITARNOS SUS DATOS?</strong></p><p data-v-716b8056>Cualquier persona tiene derecho a obtener confirmación sobre si en REGLADO GROUP S.L estamos tratando datos personales que les conciernan, o no. Las personas interesadas tienen derecho a:</p><ul data-v-716b8056><li data-v-716b8056>Acceder a sus datos personales.</li><li data-v-716b8056>Solicitar la rectificación de los datos inexactos.</li><li data-v-716b8056>Solicitar su supresión cuando los datos ya no sean necesarios.</li><li data-v-716b8056>Solicitar la limitación de su tratamiento.</li><li data-v-716b8056>Oponerse al tratamiento de sus datos.</li><li data-v-716b8056>Derecho a la portabilidad de los datos.</li></ul><p data-v-716b8056>Para ejercer estos derechos, puede dirigirse a info@regladoconsultores.com adjuntando copia de su DNI.</p></div></div>',1)])]))}},p=e(l,[["__scopeId","data-v-716b8056"]]);export{p as default};
